import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Wallet, Mail, Lock, Eye, EyeOff, ArrowRight, AlertCircle } from 'lucide-react';
import { Link } from 'react-router-dom'; // Importação necessária para o link

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    const { error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });

    if (error) {
      setError('E-mail ou senha incorretos. Tente novamente.');
      setLoading(false);
    }
  };

  const theme = {
    primary: '#4361ee',
    dark: '#0f172a',
    bg: '#f8fafc',
    surface: '#ffffff'
  };

  return (
    <div style={{ 
      minHeight: '100vh', 
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center', 
      backgroundColor: theme.bg,
      padding: '20px',
      fontFamily: "'Inter', sans-serif"
    }}>
      <div className="fade-in" style={{ 
        width: '100%', 
        maxWidth: '420px', 
        backgroundColor: theme.surface, 
        padding: '40px', 
        borderRadius: '32px',
        boxShadow: '0 20px 25px -5px rgba(0,0,0,0.05), 0 10px 10px -5px rgba(0,0,0,0.02)',
      }}>
        
        <div style={{ textAlign: 'center', marginBottom: '40px' }}>
          <div style={{ 
            background: theme.primary, 
            width: '60px', 
            height: '60px', 
            borderRadius: '18px', 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center',
            margin: '0 auto 20px auto',
            boxShadow: `0 10px 15px ${theme.primary}44`
          }}>
            <Wallet color="white" size={32} />
          </div>
          <h1 style={{ fontSize: '1.8rem', fontWeight: 800, color: theme.dark, margin: '0 0 8px 0' }}>Bem-vindo</h1>
          <p style={{ color: '#64748b', fontSize: '0.95rem' }}>Acesse sua conta para gerenciar suas finanças.</p>
        </div>

        {error && (
          <div style={{ 
            backgroundColor: '#fef2f2', 
            color: '#b91c1c', 
            padding: '12px 16px', 
            borderRadius: '12px', 
            fontSize: '0.85rem', 
            display: 'flex', 
            alignItems: 'center', 
            gap: '10px',
            marginBottom: '20px',
            border: '1px solid #fee2e2'
          }}>
            <AlertCircle size={18} />
            {error}
          </div>
        )}

        <form onSubmit={handleLogin} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
          <div>
            <label style={labelStyle}>E-mail</label>
            <div style={inputWrapperStyle}>
              <Mail size={20} color="#94a3b8" />
              <input 
                type="email" 
                placeholder="seu@email.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                style={inputStyle}
              />
            </div>
          </div>

          <div>
            <label style={labelStyle}>Senha</label>
            <div style={inputWrapperStyle}>
              <Lock size={20} color="#94a3b8" />
              <input 
                type={showPassword ? "text" : "password"} 
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                style={inputStyle}
              />
              <button 
                type="button" 
                onClick={() => setShowPassword(!showPassword)}
                style={{ background: 'none', border: 'none', cursor: 'pointer', padding: '0 5px', color: '#94a3b8' }}
              >
                {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
              </button>
            </div>
          </div>

          <div style={{ textAlign: 'right' }}>
            <a href="#" style={{ fontSize: '0.85rem', color: theme.primary, fontWeight: 600, textDecoration: 'none' }}>
              Esqueceu a senha?
            </a>
          </div>

          <button 
            type="submit" 
            disabled={loading}
            style={{ 
              backgroundColor: theme.primary, 
              color: 'white', 
              padding: '16px', 
              borderRadius: '16px', 
              border: 'none', 
              fontSize: '1rem', 
              fontWeight: 700, 
              cursor: 'pointer',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '10px',
              transition: 'all 0.2s ease',
              marginTop: '10px',
              boxShadow: `0 10px 20px ${theme.primary}33`
            }}
          >
            {loading ? 'Entrando...' : (
              <>
                Entrar na Conta <ArrowRight size={20} />
              </>
            )}
          </button>
        </form>

        {/* TEXTO ATUALIZADO COM LINK PARA REGISTRO */}
        <div style={{ textAlign: 'center', marginTop: '30px', fontSize: '0.9rem', color: '#64748b' }}>
          Não tem uma conta?{' '}
          <Link to="/registro" style={{ color: theme.primary, fontWeight: 700, textDecoration: 'none' }}>
            Cadastre-se
          </Link>
        </div>
      </div>
    </div>
  );
};

/* ESTILOS INTERNOS PERMANECEM OS MESMOS */
const labelStyle = { display: 'block', fontSize: '0.85rem', fontWeight: 700, color: '#475569', marginBottom: '8px', textTransform: 'uppercase', letterSpacing: '0.5px' };
const inputWrapperStyle = { display: 'flex', alignItems: 'center', gap: '12px', backgroundColor: '#f1f5f9', padding: '0 16px', borderRadius: '16px', border: '2px solid transparent', transition: 'all 0.2s ease', height: '56px' };
const inputStyle = { flex: 1, background: 'none', border: 'none', outline: 'none', fontSize: '1rem', color: '#0f172a', width: '100%' };

export default Login;
